package polyfunc

import (
	"fmt"
	"net/http"
)

func DocsHandler() interface{} {
	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("x-poly", "yes")
    w.WriteHeader(http.StatusAccepted)
    _, _ = w.Write([]byte(r.URL.Path))
  })
	return fmt.Sprintf("%T:%d", handler, http.StatusAccepted)
}
